insert into public.compliance_regulations
  (id, slug, locale, category, short_label, label, description, applicability, display_order, is_published)
values
  ('03f33543-debe-4223-b7c7-5be24a12fda3', 'dsgvo', 'de', 'gesetz', 'DSGVO', 'DSGVO — Datenschutz-Grundverordnung', 'EU-Verordnung 2016/679 zum Schutz natürlicher Personen bei der Verarbeitung personenbezogener Daten. Grundlage jeder datengetriebenen KI-Anwendung.', 'Gilt für jede Verarbeitung personenbezogener Daten in der EU bzw. von EU-Bürgern — unabhängig von Branche oder Unternehmensgröße.', 0, true),
  ('df8e0fb1-e132-4bab-9f9d-364f04679340', 'dsgvo', 'en', 'gesetz', 'GDPR', 'GDPR — General Data Protection Regulation', 'EU Regulation 2016/679 on the protection of natural persons with regard to the processing of personal data. Foundation of every data-driven AI application.', 'Applies to any processing of personal data in the EU or of EU citizens — regardless of industry or company size.', 0, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'eu_ai_act', 'de', 'gesetz', 'EU AI Act', 'EU AI Act — KI-Verordnung', 'EU-Verordnung 2024/1689: risikobasierter Rechtsrahmen für KI. Staffelt Pflichten nach Risikoklasse (verboten, hoch, begrenzt, minimal).', 'Gilt für Anbieter und Betreiber von KI-Systemen, die in der EU in Verkehr gebracht oder genutzt werden. Fristen gestaffelt bis 2027.', 1, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'eu_ai_act', 'en', 'gesetz', 'EU AI Act', 'EU AI Act — AI Regulation', 'EU Regulation 2024/1689: risk-based legal framework for AI. Tiers obligations by risk class (prohibited, high, limited, minimal).', 'Applies to providers and deployers of AI systems placed on the market or used in the EU. Deadlines staggered until 2027.', 1, true),
  ('ac79fd08-61ed-4448-b158-77fdbe1c860a', 'iso_42001', 'de', 'standard', 'ISO 42001', 'ISO 42001 — KI-Managementsystem', 'Internationaler Standard für den Aufbau, Betrieb und die kontinuierliche Verbesserung eines KI-Managementsystems (AIMS). Adressiert Governance, Risiko, Transparenz und ethische Aspekte.', 'Empfohlen für Unternehmen, die AI-Systeme entwickeln oder betreiben und eine zertifizierbare Governance-Grundlage anstreben.', 2, true),
  ('76dec5bd-5fc6-407c-868c-f2a6e51c562f', 'iso_42001', 'en', 'standard', 'ISO 42001', 'ISO 42001 — AI Management System', 'International standard for establishing, operating and continuously improving an AI Management System (AIMS). Addresses governance, risk, transparency and ethical aspects.', 'Recommended for organizations developing or operating AI systems that seek a certifiable governance foundation.', 2, true),
  ('3609c849-620b-43de-a045-79a5b3a0d2f8', 'nis2', 'de', 'gesetz', 'NIS-2', 'NIS-2 — Cybersicherheitsrichtlinie', 'EU-Richtlinie 2022/2555 erweitert den Geltungsbereich auf mehr Sektoren und verschärft Anforderungen an Risikomanagement, Meldepflichten und Lieferkettensicherheit.', 'Gilt für „wesentliche" und „wichtige" Einrichtungen in 18 Sektoren (u. a. Energie, Finanzen, Gesundheit, Digitale Infrastruktur). EU-Umsetzungsfrist: Oktober 2024. In Deutschland in Kraft durch das NIS2UmsuCG ab 6. Dezember 2025 (ohne Übergangsfrist).', 3, true),
  ('34c62ab0-3991-47a5-8573-474d6c566ec8', 'nis2', 'en', 'gesetz', 'NIS-2', 'NIS-2 — Cybersecurity Directive', 'EU Directive 2022/2555 expands the scope to more sectors and tightens requirements for risk management, reporting obligations and supply chain security.', 'Applies to "essential" and "important" entities in 18 sectors (incl. energy, finance, health, digital infrastructure). EU transposition deadline: October 2024. In Germany enforceable via NIS2UmsuCG from 6 December 2025 (no grace period).', 3, true),
  ('7dfcc4a5-cbb0-45c9-ba77-3d2eae3ced35', 'iso_27001', 'de', 'standard', 'ISO 27001', 'ISO 27001 — Informationssicherheit', 'International anerkannter Standard für Informationssicherheits-Managementsysteme (ISMS). Definiert Anforderungen für den systematischen Schutz von Informationswerten.', 'Relevant für alle Unternehmen, die Kundendaten verarbeiten oder in regulierten Branchen tätig sind. Häufige Voraussetzung in Enterprise-Ausschreibungen.', 4, true),
  ('c49302bf-f47f-4323-a3de-d6ef2e99efee', 'iso_27001', 'en', 'standard', 'ISO 27001', 'ISO 27001 — Information Security', 'Internationally recognized standard for Information Security Management Systems (ISMS). Defines requirements for the systematic protection of information assets.', 'Relevant for all organizations processing customer data or operating in regulated industries. Frequently required in enterprise procurement.', 4, true),
  ('52e26512-a54f-4228-a475-51e021106759', 'bait', 'de', 'aufsichtsrecht', 'BAIT', 'BAIT — Bankaufsichtliche IT-Anforderungen', 'BaFin-Rundschreiben zu IT-Governance, Informationssicherheit und IT-Risikomanagement für Kreditinstitute. Ergänzt MaRisk im IT-Bereich.', 'Verpflichtend für Kreditinstitute und Finanzdienstleister unter BaFin-Aufsicht. Besonders relevant beim Einsatz von AI in Kredit-, Scoring- oder Risikomodellen.', 5, true),
  ('10434c6b-9f08-4e3f-885a-bc653eeacb7e', 'bait', 'en', 'aufsichtsrecht', 'BAIT', 'BAIT — Banking Supervisory IT Requirements', 'BaFin circular on IT governance, information security and IT risk management for credit institutions. Supplements MaRisk in the IT domain.', 'Mandatory for credit institutions and financial services firms under BaFin supervision. Particularly relevant when using AI in credit, scoring or risk models.', 5, true),
  ('00d61b72-f35d-4bae-bb33-0c683bd2311c', 'lksg', 'de', 'gesetz', 'LkSG', 'LkSG — Lieferkettensorgfaltspflichtengesetz', 'Deutsches Gesetz zur Sorgfaltspflicht in Lieferketten (ab 1.000 MA). Verpflichtet Unternehmen, Menschenrechts- und Umweltrisiken bei direkten und indirekten Zulieferern zu identifizieren und zu beheben.', 'Gilt für Unternehmen mit ≥ 1.000 Beschäftigten in Deutschland (ab 2024). Relevant für AI-Projekte mit externen Datenbeschaffungs- oder Annotierungs-Dienstleistern.', 6, true),
  ('c68a78c8-5540-4e10-bbf3-b3f2716fe5dd', 'lksg', 'en', 'gesetz', 'LkSG', 'LkSG — Supply Chain Due Diligence Act', 'German act on corporate due diligence in supply chains (from 1,000 employees). Requires companies to identify and remediate human rights and environmental risks at direct and indirect suppliers.', 'Applies to companies with ≥ 1,000 employees in Germany (from 2024). Relevant for AI projects with external data collection or annotation service providers.', 6, true);
insert into public.compliance_checklist_items
  (regulation_id, item_key, locale, risk_class, article, source_url, last_verified, label, description, relevance, category, display_order, is_published)
values
  ('03f33543-debe-4223-b7c7-5be24a12fda3', 'dsgvo_art6', 'de', null, 'Art. 6 DSGVO', null, null, 'Rechtsgrundlage für Datenverarbeitung dokumentiert', 'Einwilligung, Vertrag, rechtliche Verpflichtung, berechtigte Interessen oder lebenswichtige Interessen — schriftlich festgehalten und im VVT hinterlegt.', 'KI-Systeme verarbeiten oft große Datenmengen zu neuen Zwecken — Zweckbindung und Rechtsgrundlage müssen explizit für den KI-Use-Case gelten.', null, 0, true),
  ('df8e0fb1-e132-4bab-9f9d-364f04679340', 'dsgvo_art6', 'en', null, 'Art. 6 DSGVO', null, null, 'Legal basis for data processing documented', 'Consent, contract, legal obligation, legitimate interests or vital interests — recorded in writing and documented in the RoPA.', 'AI systems often process large amounts of data for new purposes — purpose limitation and legal basis must explicitly apply to the AI use case.', null, 0, true),
  ('03f33543-debe-4223-b7c7-5be24a12fda3', 'dsgvo_art9', 'de', null, 'Art. 9 DSGVO', null, null, 'Besondere Datenkategorien geprüft und dokumentiert', 'Gesundheitsdaten, biometrische Daten, ethnische Herkunft, politische Meinungen, Gewerkschaftszugehörigkeit, religiöse Überzeugungen — erhöhte Anforderungen gelten.', 'Viele ML-Modelle erkennen oder inferieren besondere Datenkategorien indirekt (z. B. Gesundheitsstatus aus Kaufverhalten).', null, 1, true),
  ('df8e0fb1-e132-4bab-9f9d-364f04679340', 'dsgvo_art9', 'en', null, 'Art. 9 DSGVO', null, null, 'Special categories of data reviewed and documented', 'Health data, biometric data, ethnic origin, political opinions, trade union membership, religious beliefs — enhanced requirements apply.', 'Many ML models recognize or infer special categories of data indirectly (e.g. health status from purchasing behavior).', null, 1, true),
  ('03f33543-debe-4223-b7c7-5be24a12fda3', 'dsgvo_art13', 'de', null, 'Art. 13 / 14 DSGVO', null, null, 'Informationspflichten erfüllt (Datenschutzhinweis aktuell)', 'Betroffene Personen müssen über Zweck, Rechtsgrundlage, Empfänger, Speicherdauer und ihre Rechte informiert werden — bei Direkterhebung (Art. 13) oder Drittquelle (Art. 14).', 'Datenschutzhinweis muss explizit auf KI-Verarbeitung und automatisierte Entscheidungsfindung hinweisen.', null, 2, true),
  ('df8e0fb1-e132-4bab-9f9d-364f04679340', 'dsgvo_art13', 'en', null, 'Art. 13 / 14 DSGVO', null, null, 'Information obligations fulfilled (privacy notice up to date)', 'Data subjects must be informed about purpose, legal basis, recipients, retention period and their rights — on direct collection (Art. 13) or from third-party sources (Art. 14).', 'Privacy notice must explicitly reference AI processing and automated decision-making.', null, 2, true),
  ('03f33543-debe-4223-b7c7-5be24a12fda3', 'dsgvo_art22', 'de', null, 'Art. 22 DSGVO', null, null, 'Automatisierte Einzelentscheidungen: menschlicher Review verankert', 'Entscheidungen mit wesentlicher rechtlicher oder ähnlicher Wirkung (Kredit, Einstellung, Versicherung) dürfen nicht ausschließlich automatisiert getroffen werden.', 'Gilt direkt für KI-Entscheidungssysteme. Human-in-the-Loop ist DSGVO-Pflicht, nicht nur AI-Act-Anforderung.', null, 3, true),
  ('df8e0fb1-e132-4bab-9f9d-364f04679340', 'dsgvo_art22', 'en', null, 'Art. 22 DSGVO', null, null, 'Automated individual decisions: human review established', 'Decisions with significant legal or similarly significant effect (credit, hiring, insurance) may not be made solely by automated means.', 'Applies directly to AI decision-making systems. Human-in-the-loop is a GDPR obligation, not just an AI Act requirement.', null, 3, true),
  ('03f33543-debe-4223-b7c7-5be24a12fda3', 'dsgvo_art25', 'de', null, 'Art. 25 DSGVO', null, null, 'Privacy by Design & by Default implementiert', 'Datensparsamkeit und datenschutzfreundliche Voreinstellungen ab dem Zeitpunkt der Systemplanung technisch umgesetzt — nicht nachträglich angehängt.', 'Muss bei der KI-Systemarchitektur berücksichtigt werden: minimale Daten, keine unnecessäre Datenspeicherung.', null, 4, true),
  ('df8e0fb1-e132-4bab-9f9d-364f04679340', 'dsgvo_art25', 'en', null, 'Art. 25 DSGVO', null, null, 'Privacy by Design & by Default implemented', 'Data minimization and privacy-friendly defaults implemented technically from the point of system design — not retrofitted.', 'Must be considered in AI system architecture: minimal data, no unnecessary data storage.', null, 4, true),
  ('03f33543-debe-4223-b7c7-5be24a12fda3', 'dsgvo_art28', 'de', null, 'Art. 28 DSGVO', null, null, 'AV-Verträge mit allen Dienstleistern abgeschlossen', 'Auftragsverarbeitungsverträge (AVV) mit allen Cloud-Anbietern, ML-Plattformanbietern und Datenverarbeitern vorhanden und geprüft.', 'OpenAI, AWS, Azure, GCP, Snowflake etc. als Auftragsverarbeiter → AVV Pflicht. Daten dürfen nicht für Modelltraining genutzt werden.', null, 5, true),
  ('df8e0fb1-e132-4bab-9f9d-364f04679340', 'dsgvo_art28', 'en', null, 'Art. 28 DSGVO', null, null, 'Data processing agreements concluded with all service providers', 'Data processing agreements (DPAs) with all cloud providers, ML platform providers and data processors in place and reviewed.', 'OpenAI, AWS, Azure, GCP, Snowflake etc. as processors → DPA mandatory. Data must not be used for model training.', null, 5, true),
  ('03f33543-debe-4223-b7c7-5be24a12fda3', 'dsgvo_art30', 'de', null, 'Art. 30 DSGVO', null, null, 'Verarbeitungsverzeichnis (VVT) mit KI-Aktivitäten aktuell', 'Alle KI-Verarbeitungstätigkeiten im VVT eingetragen: Zweck, Kategorien, Empfänger, Speicherdauer, technisch-organisatorische Maßnahmen.', 'KI-Systeme als eigenständige Verarbeitungstätigkeiten eintragen — nicht einfach unter bestehende IT-Prozesse subsumieren.', null, 6, true),
  ('df8e0fb1-e132-4bab-9f9d-364f04679340', 'dsgvo_art30', 'en', null, 'Art. 30 DSGVO', null, null, 'Record of Processing Activities (RoPA) including AI activities up to date', 'All AI processing activities recorded in the RoPA: purpose, categories, recipients, retention period, technical and organizational measures.', 'AI systems must be recorded as independent processing activities — not simply subsumed under existing IT processes.', null, 6, true),
  ('03f33543-debe-4223-b7c7-5be24a12fda3', 'dsgvo_art32', 'de', null, 'Art. 32 DSGVO', null, null, 'TOMs dokumentiert (Verschlüsselung, Zugriffskontrolle, Pseudonymisierung)', 'Technisch-organisatorische Maßnahmen dem Stand der Technik entsprechend und dem Risiko angemessen schriftlich festgehalten.', 'Für KI-Systeme: Pseudonymisierung von Trainingsdaten, Verschlüsselung at-rest und in-transit, rollenbasierte Zugriffskontrollen.', null, 7, true),
  ('df8e0fb1-e132-4bab-9f9d-364f04679340', 'dsgvo_art32', 'en', null, 'Art. 32 DSGVO', null, null, 'TOMs documented (encryption, access control, pseudonymization)', 'Technical and organizational measures documented in writing, appropriate to the state of the art and proportionate to the risk.', 'For AI systems: pseudonymization of training data, encryption at rest and in transit, role-based access controls.', null, 7, true),
  ('03f33543-debe-4223-b7c7-5be24a12fda3', 'dsgvo_art35', 'de', null, 'Art. 35 DSGVO', null, null, 'DPIA durchgeführt (wenn erforderlich)', 'Datenschutz-Folgenabschätzung bei systematischer und umfangreicher Bewertung natürlicher Personen, umfangreicher Verarbeitung besonderer Kategorien oder systematischer Überwachung.', 'Hochrisiko-KI-Systeme (EU AI Act) erfordern fast immer auch eine DPIA. Beide Anforderungen gleichzeitig beachten.', null, 8, true),
  ('df8e0fb1-e132-4bab-9f9d-364f04679340', 'dsgvo_art35', 'en', null, 'Art. 35 DSGVO', null, null, 'DPIA conducted (where required)', 'Data Protection Impact Assessment required for systematic and extensive profiling of natural persons, large-scale processing of special categories, or systematic monitoring.', 'High-risk AI systems (EU AI Act) almost always also require a DPIA. Both requirements must be addressed simultaneously.', null, 8, true),
  ('03f33543-debe-4223-b7c7-5be24a12fda3', 'dsgvo_art15_22', 'de', null, 'Art. 15–22 DSGVO', null, null, 'Betroffenenrechte technisch und organisatorisch umsetzbar', 'Auskunft, Berichtigung, Löschung, Einschränkung, Widerspruch und Datenportabilität müssen für Betroffene praktisch zugänglich und innerhalb der Fristen umsetzbar sein.', 'KI-Systeme müssen "vergessen" können — Daten aus Trainingsdaten und Inferenz-Logs löschbar gestalten.', null, 9, true),
  ('df8e0fb1-e132-4bab-9f9d-364f04679340', 'dsgvo_art15_22', 'en', null, 'Art. 15–22 DSGVO', null, null, 'Data subject rights technically and organizationally exercisable', 'Access, rectification, erasure, restriction, objection and data portability must be practically accessible for data subjects and fulfillable within the statutory deadlines.', 'AI systems must be able to "forget" — data in training sets and inference logs must be deletable.', null, 9, true),
  ('03f33543-debe-4223-b7c7-5be24a12fda3', 'dsgvo_art44', 'de', null, 'Art. 44–49 DSGVO', null, null, 'Drittlandstransfers geregelt (SCCs oder Angemessenheitsbeschluss)', 'Übermittlung von Daten außerhalb des EWR nur mit gültigem Mechanismus: Angemessenheitsbeschluss (z. B. EU-US Data Privacy Framework), SCCs oder Binding Corporate Rules.', 'US-Cloud-Dienste und KI-APIs (OpenAI, Anthropic, Google AI) = Drittlandstransfer. SCCs prüfen und in AVV verankern.', null, 10, true),
  ('df8e0fb1-e132-4bab-9f9d-364f04679340', 'dsgvo_art44', 'en', null, 'Art. 44–49 DSGVO', null, null, 'Third-country transfers regulated (SCCs or adequacy decision)', 'Transfer of data outside the EEA only with a valid mechanism: adequacy decision (e.g. EU-US Data Privacy Framework), SCCs or Binding Corporate Rules.', 'US cloud services and AI APIs (OpenAI, Anthropic, Google AI) = third-country transfer. Review SCCs and anchor in DPA.', null, 10, true),
  ('03f33543-debe-4223-b7c7-5be24a12fda3', 'dsgvo_edpb_cef2026', 'de', null, 'Art. 12–14 DSGVO', 'https://www.edpb.europa.eu/news_de', '2026-07-07', 'Transparenz- und Informationspflichten EDPB-prüfsicher (Schwerpunkt 2026)', 'Der EDPB hat die Einhaltung der Transparenz- und Informationspflichten zum EU-weiten Prüfschwerpunkt 2026 erklärt (Coordinated Enforcement Framework). Datenschutzhinweise werden 2026 verstärkt auf Klarheit, Vollständigkeit und korrekte KI-Kennzeichnung geprüft.', 'KI-Systeme (Chatbots, Scoring, Profiling) müssen im Datenschutzhinweis explizit benannt werden — inkl. Angabe, ob Trainingsdaten oder Profiling betroffen sind. Copy-Paste-Datenschutzerklärungen ohne KI-Bezug sind das häufigste Prüfrisiko.', null, 11, true),
  ('df8e0fb1-e132-4bab-9f9d-364f04679340', 'dsgvo_edpb_cef2026', 'en', null, 'Art. 12–14 DSGVO', 'https://www.edpb.europa.eu/news_de', '2026-07-07', 'Transparency and information obligations EDPB audit-proof (2026 enforcement focus)', 'The EDPB has designated compliance with transparency and information obligations as the EU-wide enforcement focus for 2026 (Coordinated Enforcement Framework). Privacy notices will be increasingly scrutinized in 2026 for clarity, completeness and correct AI disclosure.', 'AI systems (chatbots, scoring, profiling) must be explicitly named in the privacy notice — including whether training data or profiling is involved. Copy-paste privacy policies without AI reference are the most common audit risk.', null, 11, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art9', 'de', 'high', 'Art. 9', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Risikomanagementsystem implementieren', 'Fortlaufendes Risikomanagementsystem für den gesamten Lebenszyklus des Hochrisiko-KI-Systems einrichten. Bekannte und vorhersehbare Risiken identifizieren, analysieren und mitigieren.', 'Grundvoraussetzung: ohne Art. 9 sind alle weiteren Hochrisiko-Pflichten nicht erfüllbar.', null, 0, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art9', 'en', 'high', 'Art. 9', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Implement a risk management system', 'Establish a continuous risk management system for the entire lifecycle of the high-risk AI system. Identify, analyze and mitigate known and foreseeable risks.', 'Prerequisite: without Art. 9, none of the other high-risk obligations can be fulfilled.', null, 0, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art10', 'de', 'high', 'Art. 10', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Daten-Governance: Trainings- und Validierungsdaten dokumentieren', 'Datenverwaltungspraktiken festlegen: Herkunft, Erhebungsmethoden, vorgesehene Zwecke, bekannte Lücken. Trainingsdaten müssen hinsichtlich Bias geprüft sein.', 'Betrifft alle genutzten oder selbst entwickelten ML-Modelle für Hochrisiko-Anwendungen.', null, 1, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art10', 'en', 'high', 'Art. 10', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Data governance: document training and validation data', 'Define data management practices: origin, collection methods, intended purposes, known gaps. Training data must be examined for bias.', 'Applies to all ML models used or developed in-house for high-risk applications.', null, 1, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art11', 'de', 'high', 'Art. 11 + Anhang IV', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Technische Dokumentation nach Anhang IV erstellen', 'Vollständige technische Dokumentation vor Inbetriebnahme erstellen und aktuell halten: Zweck, Design, Algorithmen, Daten, Testergebnisse, Risikomaßnahmen.', 'Muss für Marktüberwachungsbehörden auf Anfrage bereitstehen.', null, 2, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art11', 'en', 'high', 'Art. 11 + Anhang IV', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Create technical documentation per Annex IV', 'Create and maintain complete technical documentation before deployment: purpose, design, algorithms, data, test results, risk measures.', 'Must be available to market surveillance authorities upon request.', null, 2, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art12', 'de', 'high', 'Art. 12', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Automatische Ereignisprotokollierung (Logging) einrichten', 'Hochrisiko-KI-Systeme müssen automatisch Ereignisse protokollieren (Log-Level), die Rückverfolgbarkeit über den Lebenszyklus ermöglichen.', 'Kritisch für Post-Incident-Analysen und Konformitätsnachweise.', null, 3, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art12', 'en', 'high', 'Art. 12', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Implement automatic event logging', 'High-risk AI systems must automatically log events (log level) enabling traceability across the lifecycle.', 'Critical for post-incident analysis and conformity evidence.', null, 3, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art13', 'de', 'high', 'Art. 13', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Transparenz und Nutzerinformation sicherstellen', 'Nutzende von Hochrisiko-KI-Systemen müssen ausreichende Informationen erhalten: Zweck, Fähigkeiten und Grenzen, Überwachungshinweise.', 'Betrifft die Gebrauchsanweisung und Nutzer-Onboarding-Dokumentation.', null, 4, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art13', 'en', 'high', 'Art. 13', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Ensure transparency and user information', 'Users of high-risk AI systems must receive adequate information: purpose, capabilities and limitations, supervision instructions.', 'Applies to the instructions for use and user onboarding documentation.', null, 4, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art14', 'de', 'high', 'Art. 14', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Human Oversight verankern', 'Das System muss so gestaltet sein, dass natürliche Personen Entscheidungen wirksam überwachen, verstehen, eingreifen, stoppen oder überstimmen können.', 'Human-in-the-Loop ist Pflicht, keine Option.', null, 5, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art14', 'en', 'high', 'Art. 14', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Establish human oversight', 'The system must be designed so that natural persons can effectively monitor, understand, intervene in, stop or override decisions.', 'Human-in-the-loop is mandatory, not optional.', null, 5, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art15', 'de', 'high', 'Art. 15', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Genauigkeit, Robustheit und Cybersicherheit gewährleisten', 'System muss ausreichende Genauigkeit, Konsistenz und Widerstandsfähigkeit gegen Angriffe (Adversarial Inputs, Datenmanipulation) während des gesamten Lebenszyklus aufweisen.', 'Regelmäßige Tests und Monitoring-Prozesse sind erforderlich.', null, 6, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art15', 'en', 'high', 'Art. 15', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Ensure accuracy, robustness and cybersecurity', 'The system must demonstrate adequate accuracy, consistency and resilience against attacks (adversarial inputs, data manipulation) throughout its lifecycle.', 'Regular testing and monitoring processes are required.', null, 6, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art43', 'de', 'high', 'Art. 43', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Konformitätsbewertung durchführen', 'Vor Inbetriebnahme: interne Kontrolle (für die meisten Systeme) oder Prüfung durch benannte Stelle (für besonders kritische Systeme wie biometrische Identifikation).', 'Voraussetzung für CE-Kennzeichnung und Marktzulassung.', null, 7, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art43', 'en', 'high', 'Art. 43', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Conduct conformity assessment', 'Before deployment: internal control (for most systems) or examination by a notified body (for particularly critical systems such as biometric identification).', 'Prerequisite for CE marking and market clearance.', null, 7, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art48', 'de', 'high', 'Art. 48', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'CE-Kennzeichnung anbringen', 'Nach bestandener Konformitätsbewertung muss das KI-System mit der CE-Kennzeichnung versehen werden.', 'Rechtliche Voraussetzung für das Inverkehrbringen in der EU.', null, 8, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art48', 'en', 'high', 'Art. 48', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Affix CE marking', 'After a successful conformity assessment, the AI system must be affixed with the CE marking.', 'Legal prerequisite for placing the system on the EU market.', null, 8, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art71', 'de', 'high', 'Art. 71', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'System in EU-AI-Datenbank registrieren', 'Betreiber von Hochrisiko-KI-Systemen müssen diese vor Inbetriebnahme in der öffentlichen EU-KI-Datenbank (ai-act.eu) registrieren.', 'Ausnahme: Behörden in den Bereichen Strafverfolgung und Migration (nicht-öffentliche Datenbank).', null, 9, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art71', 'en', 'high', 'Art. 71', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Register system in the EU AI database', 'Operators of high-risk AI systems must register them in the public EU AI database (ai-act.eu) before deployment.', 'Exception: authorities in law enforcement and migration (non-public database).', null, 9, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art72', 'de', 'high', 'Art. 72', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Post-Market Monitoring einrichten', 'Fortlaufendes System zur Überwachung der Leistung nach Inbetriebnahme. Wesentliche Änderungen melden; Zwischenfälle (serious incidents) der Marktüberwachungsbehörde berichten.', 'Gilt auch für eingesetzte Drittanbieter-Modelle, wenn diese für Hochrisiko-Zwecke genutzt werden.', null, 10, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art72', 'en', 'high', 'Art. 72', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Implement post-market monitoring', 'Continuous system for monitoring performance after deployment. Report substantial modifications; report serious incidents to the market surveillance authority.', 'Also applies to third-party models deployed for high-risk purposes.', null, 10, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art50_1', 'de', 'limited', 'Art. 50 Abs. 1', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Nutzer über KI-Interaktion informieren', 'Natürliche Personen müssen bei Chatbots und interaktiven KI-Systemen klar und verständlich informiert werden, dass sie mit einem KI-System interagieren.', 'Pflicht bei jedem KI-System mit direktem Nutzerkontakt, auch intern.', null, 11, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art50_1', 'en', 'limited', 'Art. 50 Abs. 1', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Inform users about AI interaction', 'Natural persons must be clearly and comprehensibly informed when interacting with chatbots and interactive AI systems that they are engaging with an AI system.', 'Mandatory for every AI system with direct user contact, including internal systems.', null, 11, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art50_2', 'de', 'limited', 'Art. 50 Abs. 2', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'KI-generierte Inhalte maschinenlesbar kennzeichnen', 'Synthetische Audio-, Bild-, Video- und Textinhalte (Deep Fakes, generierte Medien) müssen mit einem maschinenlesbaren Marker versehen werden.', 'Gilt für alle Systeme, die synthetische Inhalte erzeugen, unabhängig vom Verwendungszweck.', null, 12, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art50_2', 'en', 'limited', 'Art. 50 Abs. 2', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Label AI-generated content in machine-readable format', 'Synthetic audio, image, video and text content (deep fakes, generated media) must be marked with a machine-readable marker.', 'Applies to all systems that generate synthetic content, regardless of purpose.', null, 12, true),
  ('4ebe2c05-89e8-4849-bbf8-24ad75787a65', 'euaiact_art50_4', 'de', 'limited', 'Art. 50 Abs. 4', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Deepfakes und synthetische Medien kennzeichnen (sichtbar)', 'Erzeugte Bilder, Videos oder Audios, die reale Personen, Orte oder Ereignisse täuschend nachahmen, müssen für Empfänger erkennbar als KI-generiert markiert sein.', 'Auch relevant bei internen Kommunikationsmaterialien oder Marketinginhalten.', null, 13, true),
  ('5880a096-dac0-4145-ab30-685cb833b781', 'euaiact_art50_4', 'en', 'limited', 'Art. 50 Abs. 4', 'https://eur-lex.europa.eu/legal-content/DE/TXT/?uri=CELEX:32024R1689', '2026-07-07', 'Label deepfakes and synthetic media (visibly)', 'Generated images, videos or audio that deceptively imitate real persons, places or events must be recognizably marked as AI-generated for recipients.', 'Also relevant for internal communication materials or marketing content.', null, 13, true),
